!function(){"use strict";const doc=document,body=doc.body,html=doc.documentElement;if(/(trident|msie)/i.test(navigator.userAgent)&&doc.getElementById&&window.addEventListener){window.addEventListener("hashchange",()=>{const id=location.hash.slice(1);if(!/^[A-z0-9_-]+$/.test(id)){return}const el=doc.getElementById(id);if(!el){return}if(!/^(?:a|select|input|button|textarea)$/i.test(el.tagName)){el.tabIndex=-1}el.focus()},false)}if(!("querySelector"in doc&&"addEventListener"in window)){return}body.addEventListener("mousedown",()=>body.classList.add("using-mouse"));body.addEventListener("keydown",()=>body.classList.remove("using-mouse"));if(!body.classList.contains("dropdown-hover")){return}for(const a of doc.querySelectorAll("nav .main-nav ul a")){const handler=function(){if(this.closest("nav").classList.contains("toggled")||this.closest("nav").classList.contains("slideout-navigation")){return}let el=this;while(el.className.indexOf("main-nav")===-1){if(el.tagName.toLowerCase()==="li"){el.className=el.className.includes("sfHover")?el.className.replace(" sfHover",""):el.className+" sfHover"}el=el.parentElement}};a.addEventListener("focus",handler);a.addEventListener("blur",handler)}if(!("ontouchend"in html)){return}for(const li of doc.querySelectorAll(".sf-menu .menu-item-has-children")){li.addEventListener("touchend",function(e){const nav=this.closest("nav");if(nav.classList.contains("toggled")){return}if(e.touches.length!==1&&e.touches.length!==0){return}e.stopPropagation();if(this.classList.contains("sfHover")){return}const tgt=e.target;if(tgt===this||tgt.parentNode===this||tgt.parentNode?.parentNode===this){e.preventDefault()}const open=nav.querySelectorAll("ul.toggled-on");if(open&&!this.closest("ul").classList.contains("toggled-on")&&!this.closest("li").classList.contains("sfHover")){for(const ul of open){ul.classList.remove("toggled-on");ul.closest("li").classList.remove("sfHover")}}this.classList.add("sfHover");const self=this;const onEnd=e=>{e.stopPropagation();self.classList.remove("sfHover");doc.removeEventListener("touchend",onEnd)};doc.addEventListener("touchend",onEnd)})}}();
